import { useState } from "react";
import base from "./pizza_base.png";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️"];

const toppingPrices = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
};

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function handlePizzaClick(event) {
    const topping = {
      emoji: selected,
      x: event.clientX,
      y: event.clientY,
    };

    setPizza([...pizza, topping]);
  }

  function calculateTotal() {
    let total = 299;
    for (const topping of pizza) {
      total += toppingPrices[topping.emoji] || 0;
    }
    return total;
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>
        <strong>Total:</strong> ₹{calculateTotal()}
      </h2>

      <p>
        {toppings.map((topping) => (
          <button
            key={topping}
            onClick={() => setSelected(topping)}
            disabled={selected === topping}
          >
            {topping}
          </button>
        ))}
      </p>

      <figure
        onClick={handlePizzaClick}
      >
        <img src={base}/>

        {
			pizza.map((topping, index) => (
				<span
					key={index}
					style={{
					position: "fixed",
					left: topping.x,
					top: topping.y,
					fontSize: "2rem",
					pointerEvents: "none",
					}
				}
				>
					{topping.emoji}
				</span>
			))
		}
      </figure>
    </main>
  );
}
